import java.nio.file.Path;
import java.nio.file.Paths;
import java.nio.file.Files;
import java.util.Scanner;

public class SecurePathTraversal {

    private static final String BASE_DIRECTORY = "C:/Users/Admin/Documents/";

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter file name: ");
        String fileName = scanner.next();

        Path filePath = Paths.get(BASE_DIRECTORY, fileName).toAbsolutePath().normalize();

        if (!filePath.startsWith(Paths.get(BASE_DIRECTORY))) {
            System.err.println("Access to files outside the base directory is not allowed.");
            return;
        }

        try {
            byte[] content = Files.readAllBytes(filePath);
            System.out.println(new String(content));
        } catch (Exception e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
    }
}

